#!/usr/bin/env node
// Build the extracted dashboard app and inline its single self-contained
// index.html into a TS constant the harness imports (see ADR 0001). This keeps
// deployment to one binary while the frontend source lives in a real Vite app.
//
//   node scripts/build-frontend.mjs
//
// The generated file is a build artifact — gitignored, never hand-edited.
import { execFileSync } from "node:child_process";
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const app = resolve(root, "apps/dashboard");

execFileSync("npm", ["run", "build", "-w", "@loom/dashboard"], { cwd: root, stdio: "inherit" });

const html = readFileSync(resolve(app, "dist/index.html"), "utf8");
// Escape for a JS template literal: backslash, backtick, and ${ interpolation.
const escaped = html.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
const banner = "// AUTO-GENERATED by scripts/build-frontend.mjs from apps/dashboard — do not edit.\n";
const out = resolve(root, "src/harness/dashboard.generated.ts");
writeFileSync(out, `${banner}export const DASHBOARD_HTML = \`${escaped}\`;\n`, "utf8");
console.log(`wrote ${out} (${html.length} bytes of HTML)`);
